chapterList.requestInfo:
@js:
function absUrl(u, base) {
  if (!u) return '';
  u = String(u).split('\\/').join('/');
  if (/^https?:\/\//i.test(u)) return u;
  if (/^\/\//.test(u)) return 'https:' + u;
  var b = base || config.host;
  var hm = String(b).match(/^(https?:\/\/[^\/]+)/i);
  var h = hm ? hm[1] : config.host;
  if (/^\//.test(u)) return h + u;
  return String(b).replace(/[^\/]*$/, '') + u;
}
if (params && params.lastResponse && params.lastResponse.nextPageUrl) {
  return {"url": absUrl(params.lastResponse.nextPageUrl, params.responseUrl), "POST": false, "httpHeaders": config.httpHeaders};
}
var u = '';
if (params && params.queryInfo) u = params.queryInfo.detailUrl || params.queryInfo.url || '';
if (!u && result) u = result.detailUrl || result.url || result;
u = absUrl(u, config.host);
if (!/\/catalog\/?(\d+\.html)?$/i.test(u)) {
  u = u.replace(/#.*$/, '').replace(/\/+$/, '') + '/catalog/';
}
return {"url": u, "POST": false, "httpHeaders": config.httpHeaders};

chapterList.nextPageUrl:
//*[@id='end']/@href||@js:
function pageNo(u) {
  var m = String(u || '').match(/\/(\d+)\.html/);
  return m ? parseInt(m[1], 10) : 1;
}
var max = pageNo(result);
var cur = 1;
if (params && params.responseUrl) cur = pageNo(params.responseUrl);
if (cur < 1) cur = 1;
if (max > cur) return String(cur + 1) + '.html';
return '';

