chapterContent.content:
@js:
/*
废文正文解密逻辑：页面中提取 d("密文", "密钥")；MD5(密钥) 前 16 位为 key，后 16 位为 iv；AES/CBC/PKCS5Padding 解 Base64。
TODO: 香色闺阁 2.56.1 的 JS 环境需实测 MD5/AES 函数名。此处依次尝试 java.*、CryptoJS、全局 md5。
*/
function pickCrypto() {
  var md5Fn = null;
  var aesFn = null;
  if (typeof java !== 'undefined') {
    if (typeof java.md5Encode === 'function') md5Fn = function (s) { return java.md5Encode(s); };
    if (typeof java.aesBase64DecodeToString === 'function') aesFn = function (text, iv, alg, key) { return java.aesBase64DecodeToString(text, iv, alg, key); };
  }
  if (typeof md5 === 'function') md5Fn = function (s) { return md5(s); };
  if (typeof CryptoJS !== 'undefined' && CryptoJS.MD5 && CryptoJS.AES && CryptoJS.enc) {
    md5Fn = function (s) { return CryptoJS.MD5(s).toString(); };
    aesFn = function (text, iv, alg, key) {
      var decrypted = CryptoJS.AES.decrypt(text, CryptoJS.enc.Utf8.parse(key), {
        iv: CryptoJS.enc.Utf8.parse(iv),
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7
      });
      return decrypted.toString(CryptoJS.enc.Utf8);
    };
  }
  return {md5: md5Fn, aes: aesFn};
}
function d(cipherText, seed) {
  var crypto = pickCrypto();
  if (!crypto.md5 || !crypto.aes) return 'TODO: 当前香色 JS 环境未确认 MD5/AES 函数。请看 README-fewen.md，并反馈 App 报错。';
  var hash = String(crypto.md5(seed));
  var key = hash.substring(0, 16);
  var iv = hash.substring(16, 32);
  return crypto.aes(cipherText, iv, 'AES/CBC/PKCS5Padding', key);
}
var html = String(result || '');
var m = html.match(/d\("([\s\S]+?)"\s*,\s*"([\s\S]+?)"\)/);
if (!m) return 'TODO: 未在章节页匹配到 d("密文", "密钥")。请提供脱敏章节 HTML 片段。';
return d(m[1], m[2]);

